public class Solution {

    private static final int MOD = 1_000_000_007;
    private static final int MAX_VALUE = 5000;
    private static final int MAX_SUM = 50;

    private int getDigitSum(int n) {
        if (n < 0) return -1; // Should not happen based on constraints
        int sum = 0;
        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }
        return sum;
    }

    public static long solve(long[] digitSum) {
        // Since digitSum[i] <= 50, we precalculate possible numbers up to 5000

        // Step 1: Precalculation of possible numbers for each digit sum
        List<Integer>[] possibleNumbers = new ArrayList[MAX_SUM + 1];
        for (int s = 0; s <= MAX_SUM; s++) {
            possibleNumbers[s] = new ArrayList<>();
        }

        for (int v = 0; v <= MAX_VALUE; v++) {
            int s = getDigitSum(v);
            if (s <= MAX_SUM) {
                possibleNumbers[s].add(v);
            }
        }

        int N = digitSum.length;

        // DP Setup: We use two arrays to store DP states for the current and previous index.
        // DP[v] stores the number of valid sequences ending with value v.
        long[] dpPrev = new long[MAX_VALUE + 1];
        long[] dpCurr = new long[MAX_VALUE + 1];

        // --- Initialization (i = 0) ---
        int s0 = (int) digitSum[0];
        if (s0 > MAX_SUM) return 0; // Should not happen based on constraints

        for (int v : possibleNumbers[s0]) {
            dpPrev[v] = 1;
        }

        // --- DP Iteration (i = 1 to N-1) ---
        for (int i = 1; i < N; i++) {
            int si = (int) digitSum[i];
            if (si > MAX_SUM) return 0;

            // Reset current DP state
            java.util.Arrays.fill(dpCurr, 0);

            // Calculate prefix sums of dpPrev (S_prev[k] = sum(dpPrev[u] for u <= k))
            long[] prefixSumPrev = new long[MAX_VALUE + 1];
            prefixSumPrev[0] = dpPrev[0];
            for (int k = 1; k <= MAX_VALUE; k++) {
                prefixSumPrev[k] = (prefixSumPrev[k-1] + dpPrev[k]) % MOD;
            }

            // Transition: Calculate dpCurr[v]
            for (int v : possibleNumbers[si]) {
                // dpCurr[v] = Sum(dpPrev[u] for u <= v) = prefixSumPrev[v]
                dpCurr[v] = prefixSumPrev[v];
            }

            // Move current state to previous state for the next iteration
            // Swap dpPrev and dpCurr (or copy)
            long[] temp = dpPrev;
            dpPrev = dpCurr;
            dpCurr = temp;
        }

        // --- Final Result ---
        long totalCount = 0;
        for (int v = 0; v <= MAX_VALUE; v++) {
            totalCount = (totalCount + dpPrev[v]) % MOD;
        }

        return totalCount;
    }
