public class Solution {

    private static final int MOD = 1_000_000_007;
    private static final int V_LIMIT = 5000;

    // Helper function to calculate the sum of digits of a number
    private static int calculateDigitSum(int n) {
        int sum = 0;
        String s = String.valueOf(n);
        for (char c : s.toCharArray()) {
            sum += c - '0';
        }
        return sum;
    }

    public static long solve(long[] digitSum) {
        int N = digitSum.length;

        // DP_prev[v]: Number of ways to form a valid prefix ending at element i-1 with value v.
        // We use long because we are dealing with counts modulo MOD.
        long[] dpPrev = new long[V_LIMIT + 1];

        // Base Case: i = 0
        int targetSum0 = (int) digitSum[0];
        for (int v = 0; v <= V_LIMIT; v++) {
            if (calculateDigitSum(v) == targetSum0) {
                dpPrev[v] = 1;
            }
        }

        // Iterate through the remaining elements (i = 1 to N-1)
        for (int i = 1; i < N; i++) {
            int targetSumI = (int) digitSum[i];
            long[] dpCurr = new long[V_LIMIT + 1];

            // 1. Calculate Prefix Sums of dpPrev
            // P_sum[v] = sum(dpPrev[u] for u=0 to v)
            long[] pPrevSum = new long[V_LIMIT + 1];
            long currentSum = 0;
            for (int v = 0; v <= V_LIMIT; v++) {
                currentSum = (currentSum + dpPrev[v]) % MOD;
                pPrevSum[v] = currentSum;
            }

            // 2. Calculate dpCurr based on transitions
            for (int v = 0; v <= V_LIMIT; v++) {
                if (calculateDigitSum(v) == targetSumI) {
                    // DP[i][v] = Sum(DP[i-1][u] for u <= v)
                    dpCurr[v] = pPrevSum[v];
                } else {
                    dpCurr[v] = 0;
                }
            }

            // Update dpPrev for the next iteration
            dpPrev = dpCurr;
        }

        // Final Result: Sum up all entries in the final DP array (dpPrev)
        long totalCount = 0;
        for (int v = 0; v <= V_LIMIT; v++) {
            totalCount = (totalCount + dpPrev[v]) % MOD;
        }

        return totalCount;
    }
}

