            long[] dpCurr = new long[V_LIMIT + 1];

            // 1. Calculate Prefix Sums of dpPrev
            // P_sum[v] = sum(dpPrev[u] for u=0 to v)
            long[] pPrevSum = new long[V_LIMIT + 1];
            long currentSum = 0;
            for (int v = 0; v <= V_LIMIT; v++) {
                currentSum = (currentSum + dpPrev[v]) % MOD;
                pPrevSum[v] = currentSum;
            }

            // 2. Calculate dpCurr based on transitions
            for (int v = 0; v <= V_LIMIT; v++) {
                if (calculateDigitSum(v) == targetSumI) {
                    // DP[i][v] = Sum(DP[i-1][u] for u <= v)
                    dpCurr[v] = pPrevSum[v];
                } else {
                    dpCurr[v] = 0;
                }
            }

            // Update dpPrev for the next iteration
            dpPrev = dpCurr;
        }

        // Final Result: Sum up all entries in the final DP array (dpPrev)
        long totalCount = 0;
        for (int v = 0; v <= V_LIMIT; v++) {
            totalCount = (totalCount + dpPrev[v]) % MOD;
        }

        return totalCount;
    }
}
